groupButtonf1mwztqves.onClick:
{{
(async () => {
  if (appsmith.store.cv_saving === true) {
    showAlert("Ya hay un guardado en proceso.", "warning");
    return;
  }

  if (!appsmith.store.cv_exportacion_id) {
    showAlert("Primero selecciona una operación.", "warning");
    return;
  }

  if (!slCvTipoDocumento.selectedOptionValue) {
    showAlert("Selecciona el tipo de documento.", "warning");
    return;
  }

  if (!inpCvProformaNo.text) {
    showAlert("Ingresa el número de proforma.", "warning");
    return;
  }

  if (!dpCvFechaProforma.selectedDate) {
    showAlert("Selecciona la fecha de la proforma.", "warning");
    return;
  }

  if (!slCvCentroCostoVenta.selectedOptionValue) {
    showAlert("Selecciona el centro de costo.", "warning");
    return;
  }

  if (!slCvFormaPago.selectedOptionValue) {
    showAlert("Selecciona la forma de pago.", "warning");
    return;
  }

  if (!slCvMoneda.selectedOptionValue) {
    showAlert("Selecciona la moneda.", "warning");
    return;
  }

  if (!slCvEstado.selectedOptionValue) {
    showAlert("Selecciona el estado.", "warning");
    return;
  }

  if (!(appsmith.store.cv_items_proforma || []).length) {
    showAlert("Agrega al menos un ítem a la proforma.", "warning");
    return;
  }

  try {
    await storeValue("cv_saving", true);

    await qCvExisteProforma.run();

    if ((qCvExisteProforma.data || []).length > 0) {
      showAlert("Ya existe una proforma con ese número para esta operación.", "warning");
      return;
    }

    await bkCvInsertProforma.run();
    await bkCvInsertProformaDetalle.run();

    await storeValue("cv_has_pending_changes", false);

    showAlert("Proforma guardada correctamente.", "success");

    await JS_CvForm.resetProformaForm();

    await qCvProformasResumen.run();
    await qCvOperacionTotales.run();
  } catch (err) {
    showAlert("Error al guardar la proforma: " + (err.message || err), "error");
  } finally {
    await storeValue("cv_saving", false);
  }
})();
}}

groupButtonn15izot6di.onClick:
{{
(async () => {
  const row = tblCvProformasResumen.selectedRow;

  if (!row || !row.id) {
    showAlert("Selecciona una proforma para eliminar.", "warning");
    return;
  }

  await storeValue("delete_context", {
    action: "DELETE_CV_PROFORMA",
    id: row.id,
    label: row.proforma_no || row.id,
    message: "Vas a eliminar la proforma " + (row.proforma_no || row.id) + ". Esta acción requiere contraseña."
  });

  resetWidget("inpDeletePassword", true);
  showModal("mdlConfirmDelete");
})();
}}

